import { db } from "@/db";
import { styles } from "@/db/schema";
import { eq } from "drizzle-orm";

export async function findStyle(idOrSlug: string) {
  let [style] = await db.select().from(styles).where(eq(styles.id, idOrSlug));
  if (!style) {
    [style] = await db.select().from(styles).where(eq(styles.slug, idOrSlug));
  }
  return style ?? null;
}
