import { sqliteTable, text, integer } from "drizzle-orm/sqlite-core";
import { relations } from "drizzle-orm";

export const styles = sqliteTable("styles", {
  id: text("id").primaryKey(),
  name: text("name").notNull(),
  slug: text("slug").notNull().unique(),
  description: text("description"),
  philosophy: text("philosophy"),
  skillContent: text("skill_content").notNull(),
  authorName: text("author_name").notNull(),
  authorUrl: text("author_url"),
  thumbnailUrl: text("thumbnail_url"),
  previewHtml: text("preview_html"),
  forkedFromId: text("forked_from_id").references((): any => styles.id),
  version: integer("version").notNull().default(1),
  tags: text("tags"),
  likesCount: integer("likes_count").notNull().default(0),
  forksCount: integer("forks_count").notNull().default(0),
  createdAt: text("created_at").notNull(),
  updatedAt: text("updated_at").notNull(),
  skinCss: text("skin_css"),
});

export const corpusImages = sqliteTable("corpus_images", {
  id: text("id").primaryKey(),
  styleId: text("style_id")
    .notNull()
    .references(() => styles.id),
  url: text("url").notNull(),
  source: text("source"),
  caption: text("caption"),
  createdAt: text("created_at").notNull(),
});

export const stylePages = sqliteTable("style_pages", {
  id: text("id").primaryKey(),
  styleId: text("style_id")
    .notNull()
    .references(() => styles.id),
  pageType: text("page_type").notNull(),
  htmlContent: text("html_content").notNull(),
  screenshotUrl: text("screenshot_url"),
  createdAt: text("created_at").notNull(),
});

export const styleVersions = sqliteTable("style_versions", {
  id: text("id").primaryKey(),
  styleId: text("style_id")
    .notNull()
    .references(() => styles.id),
  version: integer("version").notNull(),
  skillContent: text("skill_content").notNull(),
  changelog: text("changelog"),
  createdAt: text("created_at").notNull(),
});

// Relations
export const stylesRelations = relations(styles, ({ one, many }) => ({
  forkedFrom: one(styles, {
    fields: [styles.forkedFromId],
    references: [styles.id],
  }),
  corpusImages: many(corpusImages),
  pages: many(stylePages),
  versions: many(styleVersions),
}));

export const corpusImagesRelations = relations(corpusImages, ({ one }) => ({
  style: one(styles, {
    fields: [corpusImages.styleId],
    references: [styles.id],
  }),
}));

export const stylePagesRelations = relations(stylePages, ({ one }) => ({
  style: one(styles, {
    fields: [stylePages.styleId],
    references: [styles.id],
  }),
}));

export const styleVersionsRelations = relations(styleVersions, ({ one }) => ({
  style: one(styles, {
    fields: [styleVersions.styleId],
    references: [styles.id],
  }),
}));
